{
  "ai_tool": "Auspex",
  "task": "Threat Modeling",
  "description": "Auspex is an AI-powered tool designed to generate threat models for systems based on user-provided system representations, such as textual descriptions or system architecture diagrams. It leverages a technique called 'tradecraft prompting' to encode detailed threat modeling practices into prompts and prompt chains, enabling it to produce high-quality threat matrices without relying on agent-based add-ons.",
  "key_features": {
    "tradecraft_prompting": "A human-driven approach that encodes detailed threat modeling practices into prompts, allowing the system to capture nuanced threat modeling knowledge.",
    "modular_and_extensible": "Designed to be lightweight, flexible, and easily adaptable to new threat modeling methodologies or frameworks.",
    "system_representation_mapping": "Maps system descriptions to threat models by first converting system representations into solution descriptions (Stage 1), and then mapping those to threat scenarios with associated threat types and security categorizations (Stage 2).",
    "no_fine-tuning_required": "Unlike some other AI-based threat modeling tools, Auspex does not require fine-tuning or prompt optimization, relying instead on structured, detailed prompting techniques."
  },
  "comparison_to_related_work": {
    "Cyber Sentinel": "Focuses on threat identification and response through LLM-supported processing of cybersecurity logs, but lacks the structured threat modeling capabilities of Auspex.",
    "Elsharef et al.": "Uses retrieval-augmented generation (RAG) methods and lacks the structured threat modeling task and output structure that Auspex provides.",
    "STRIDE GPT": "Generates threat models with STRIDE threat types but uses brief textual prompts and lacks the detailed tradecraft prompting that Auspex employs.",
    "PILLAR": "Uses a privacy-centered LINDDUN framework and multi-agent approaches, but lacks the structured threat modeling task and output structure that Auspex provides.",
    "ThreatModeling-LLM": "Incorporates fine-tuning and prompt engineering methods, but Auspex avoids these in favor of tradecraft prompting, making it more efficient and adaptable."
  },
  "evaluation": {
    "method": "Subject matter expert feedback on Auspex-generated threat models over real banking systems.",
    "results": "The evaluation captures expert judgments on the overall value of Auspex in carrying out the threat modeling process, showing that it is perceived as valuable and effective in generating high-quality threat matrices.",
    "limitations": "No formal evaluation results are presented, and the tool is still in development with plans for expansion."
  },
  "conclusion": "Auspex represents a significant advancement in AI-based threat modeling by integrating detailed threat modeling practices into its prompting structure, avoiding the need for fine-tuning or agent-based add-ons, and providing a structured, extensible framework for generating high-quality threat matrices."
}

