        "LM (Last Mile time)",
        "O2R (Order to Reached time)"
      ]
    },
    "model_architecture": {
      "design": {
        "type": "MIMO (Multi-input, Multi-output) deep learning model",
        "shared_components": [
          "Inputs (numerical and categorical features)",
          "Hidden layers",
          "Entity embeddings"
        ],
        "reason_for_choice": "To capture interdependencies between different legs of the delivery journey (e.g., O2A + FM + WT + LM = O2R) and improve performance through shared embeddings."
      },
      "entity_embeddings": {
        "purpose": "To encode categorical variables with high cardinality (e.g., restaurant IDs, customer geo-hashes) without the curse of dimensionality.",
        "benefits": [
          "Dimensionality reduction",
          "Semantic understanding of categorical variables",
          "Improved model performance through better feature representation"
        ]
      }
