        "System stress (active DEs vs active orders)",
        "Historical assignment and first mile time behavior",
        "Near real-time behavior for deviation from historical patterns"
      ],
      "last_mile": [
        "Distance from restaurant to customer",
        "Historical speed patterns",
        "Near real-time speed patterns"
      ],
      "time_series_and_seasonality": [
        "Hourly and weekly seasonality in travel times",
        "Recency factors in feature construction"
