{
  "system": {
    "name": "LLM-Powered Personalization System",
    "description": "A hybrid system that leverages Large Language Models (LLMs) and traditional machine learning (ML) techniques to personalize grocery recommendations based on restaurant order history.",
    "components": [
      {
        "name": "Tagset Generation",
        "description": "Converts restaurant orders into structured tagsets representing dish, cuisine, and dietary attributes."
      },
      {
        "name": "Tagset-to-Taxonomy Mapping",
        "description": "Maps tagsets to grocery taxonomies using a combination of LLMs and retrieval augmented generation (RAG) techniques."
      },
      {
        "name": "Scoring Model",
        "description": "Computes relevance scores for taxonomies based on recency and frequency of tagset usage."
      },
      {
        "name": "LLM Judge System",
        "description": "Uses LLMs to evaluate the quality of tagset-to-taxonomy mappings and scoring models."
      },
      {
        "name": "Recommendation Engine",
        "description": "Generates personalized grocery recommendations based on the scored taxonomies."
      },
      {
        "name": "A/B Testing & Feedback Loop",
        "description": "Monitors user interaction with recommendations and iterates on the system using consumer feedback and performance metrics."
      }
    ],
    "metrics": [
      {
        "name": "Conversion Rate",
        "description": "Percentage of users who complete a purchase after interacting with the feature."
      },
      {
        "name": "Add-to-Cart Rate",
        "description": "Frequency with which users add items to their shopping cart after exposure to recommendations."
      },
      {
        "name": "Order Rate",
        "description": "Overall rate at which users place orders, reflecting the feature's impact on transaction volume."
      },
      {
        "name": "nDCG@3",
        "description": "Order-aware ranking quality for the top three recommendations."
      },
      {
        "name": "Precision@3",
        "description": "Fraction of the top three items whose judge scores were greater than or equal to 3."
      },
      {
        "name": "Mean Absolute Error",
        "description": "Average absolute difference between paired scores, with lower being better."
      },
      {
        "name": "Quadratic Weighted Kappa",
        "description": "Agreement on ordinal labels; penalizes larger disagreements more strongly than linear weighting."
      }
    ],
    "next_steps": [
      {
        "name": "Expand LLM-Powered Carousels",
        "description": "Broaden the use of LLM-powered recommendation carousels to more use cases beyond restaurant data."
      },
      {
        "name": "Improve Prompt Engineering",
        "description": "Refine prompt engineering techniques to further enhance the accuracy and consistency of LLM outputs."
      },
      {
        "name": "Integrate with More Verticals",
        "description": "Extend the system to other business verticals beyond grocery and convenience."
      },
      {
        "name": "Enhance Personalization",
        "description": "Refine the scoring model and recommendation engine to deliver more accurate and relevant recommendations."
      }
    ]
  },
  "key_insights": [
    {
      "title": "LLMs Shine in Cold-Start Settings",
      "description": "LLMs are particularly effective when historical data is sparse or siloed across verticals, allowing them to infer preferences from adjacent text-like data such as restaurant order tags."
    },
    {
      "title": "Structure Beats Raw Text",
      "description": "Representing history as structured tagsets and reusing precomputed mappings keeps context compact and stable, improving both performance and interpretability."
    },
    {
      "title": "RAG Reduces Hallucinations",
      "description": "Narrowing the candidate taxonomy space before prompting the LLM improves accuracy and consistency, reducing the risk of hallucinations."
    },
    {
      "title": "Hybrid Stacks Win",
      "description": "Combining LLM-generated signals with proven IR/ML systems, TTE for retrieval, and MTML for ranking helps deliver relevant and high-quality recommendations."
    },
    {
      "title": "Evaluate with LLM Judges",
      "description": "Using LLM judges to evaluate model outputs allows for rapid iteration on prompts and calibration, improving the overall quality of the system."
    }
  ]
}

{
  "llm_used": "GPT-4o",
  "key_insights": {
    "llm_integration": {
      "description": "DoorDash has implemented a comprehensive LLM-powered evaluation system called AutoEval to assess search relevance across their platform.",
      "details": [
        "AutoEval is a human-in-the-loop system that uses LLMs to evaluate search results based on structured prompts and internal rating guidelines.",
        "The system is designed to scale, reduce manual effort, and improve the accuracy of relevance judgments.",
        "LLMs are fine-tuned on expert-labeled data to align with human evaluation standards."
      ]
    },
    "prompt_engineering": {
      "description": "Prompt design is a core component of AutoEval's effectiveness.",
      "details": [
        "Prompts are structured to reflect internal rating guidelines, including user intent, document type, and relevance criteria.",
        "Various prompting strategies (zero-shot, few-shot, structured templates) are tested, with structured prompts showing the best performance.",
        "Techniques like chain-of-thought reasoning, contextual grounding, and embedded guidelines are used to improve LLM judgment quality."
      ]
    },
    "human_in_the_loop": {
      "description": "Human expertise is integrated into the evaluation process to ensure quality and alignment.",
      "details": [
        "External raters audit LLM-generated judgments, flagging low-quality outputs for internal experts to investigate.",
        "A feedback loop is maintained between human raters and the model, leading to prompt refinement and model fine-tuning.",
        "Experts justify their annotations to guide model training and ensure alignment with human expectations."
      ]
    },
    "fine_tuning": {
      "description": "LLMs are fine-tuned on high-quality, human-labeled data to improve accuracy and alignment.",
      "details": [
        "Internal DoorDash experts generate a 'golden dataset' of relevance annotations, which is used for model training and evaluation.",
        "Fine-tuned models improve performance in key categories like store name search, cuisine search, and dish/item search.",
        "The fine-tuning process includes model evaluation, prompt refinement, and ongoing iteration."
      ]
    },
    "impact_and_results": {
      "description": "AutoEval has delivered significant improvements in throughput, efficiency, and accuracy.",
      "details": [
        "Turnaround time for relevance judgments has been reduced by 98% compared to human evaluation.",
        "Expert raters are now focused on guideline development, auditing, and edge case resolution, improving overall quality.",
        "Fine-tuned LLMs consistently match or outperform external raters in key relevance tasks."
      ]
    },
    "future_directions": {
      "description": "DoorDash has outlined several future directions for improving AutoEval and LLM integration.",
      "details": [
        "Decoupling from a single LLM provider by using an internal GenAI gateway to enable vendor comparison and experimentation.",
        "Exploring in-house LLMs for greater control, cost efficiency, and domain-specific alignment.",
        "Enhancing prompt context with external knowledge sources to better handle tail queries and unfamiliar entities."
      ]
    }
  },
  "conclusion": {
    "summary": "AutoEval represents a successful integration of LLMs, prompt engineering, and human expertise to create a scalable, reliable, and efficient evaluation system for search relevance.",
    "key_takeaways": [
      "LLMs are central to scaling evaluation processes and reducing manual effort.",
      "Prompt engineering and human-in-the-loop feedback are critical for ensuring model alignment with human standards.",
      "Fine-tuning on expert data improves accuracy and consistency in relevance judgments.",
      "Future work includes vendor flexibility, in-house LLMs, and enhanced contextual understanding."
    ]
  },
  "recommendations": {
    "for_implementation": [
      "Invest in structured prompt engineering to ensure LLMs align with human evaluation criteria.",
      "Maintain a feedback loop between human raters and models to refine prompts and improve model performance.",
      "Use internal data and domain-specific knowledge to fine-tune models for better accuracy.",
      "Explore multi-vendor LLM integration to optimize cost, latency, and accuracy trade-offs."
    ],
    "for_research": [
      "Invest in in-house LLM development for domain-specific tasks and cost efficiency.",
      "Enhance prompt context with external knowledge sources to improve handling of tail queries.",
      "Continuously experiment with different prompting strategies to optimize model performance."
    ]
  }
}

