{
  "system": {
    "name": "DoorDash GenAI Content System",
    "purpose": "Enhance user engagement and discovery by generating personalized carousel content using large language models (LLMs) and metadata-driven retrieval.",
    "components": [
      {
        "name": "Carousel Title Generation",
        "description": "LLMs generate dynamic, personalized carousel titles based on user preferences, time of day, and dietary habits.",
        "features": [
          "Personalization based on user order history and cuisine preferences",
          "Contextual awareness (day-of-week, part-of-day)",
          "Topic balancing to avoid overly specific or broad titles",
          "Diversity in title generation to prevent repetition"
        ]
      },
      {
        "name": "Metadata Generation",
        "description": "LLMs create auxiliary metadata for each carousel to align with merchant profiles and user preferences.",
        "features": [
          "Integration of user preferences and order history",
          "Alignment with merchant food types and dietary options",
          "Support for personalized queries (e.g., Indian vs. American wraps)"
        ]
      },
      {
        "name": "Content Moderation",
        "description": "LLMs are used to review and block inappropriate or policy-violating carousel titles.",
        "features": [
          "LLM-as-jury approach with three independent models",
          "Veto process for blocking violations",
          "95% recall on detecting bad titles"
        ]
      },
      {
        "name": "Store and Dish Retrieval",
        "description": "LLM-generated embeddings are used to find the most relevant stores and dishes for each carousel.",
        "features": [
          "Exact KNN search on GPU for low-latency retrieval",
          "Pre-generated masks for geolocation and item availability",
          "Cosine similarity between query and document embeddings"
        ]
      },
      {
        "name": "Ranking and Presentation",
        "description": "A hybrid ranking system combines engagement signals with embedding similarity scores.",
        "features": [
          "FinalScore = R(s)^α · S(s)^β",
          "Block re-ranking for flexible experimentation",
          "Balanced approach between engagement and relevance"
        ]
      },
      {
        "name": "Evaluation and A/B Testing",
        "description": "System performance is evaluated using both internal and third-party metrics.",
        "features": [
          "Precision@10 improved from 68% to 85%",
          "A/B tests in San Francisco and Manhattan show double-digit click rate improvements",
          "Increased merchant discovery and SMB volume"
        ]
      }
    ],
    "future_work": [
      {
        "area": "Carousel Scope Expansion",
        "description": "Broaden the scope of carousels to include affordability, speed, and non-restaurant shopping (e.g., groceries)."
      },
      {
        "area": "LLM Fine-Tuning",
        "description": "Fine-tune LLMs with DoorDash-specific data to improve recommendations with co-purchase patterns, regional preferences, and store performance."
      }
    ],
    "impact": {
      "user_engagement": "Improved click-through rates and homepage relevance",
      "merchant_discovery": "Increased exposure to new cuisines and merchants",
      "SMB_growth": "Driving growth for small and mid-sized businesses"
    }
  },
  "key_metrics": {
    "precision_at_10": "85%",
    "click_rate_improvement": "Double-digit",
    "merchant_discovery_increase": "Significant",
    "smb_volume_growth": "Positive"
  },
  "technical_notes": {
    "embedding_models": "LLM text embedding models used for both carousel titles and merchant profiles",
    "retrieval_method": "Exact KNN search on GPU for low-latency retrieval",
    "moderation_accuracy": "95% recall on detecting bad titles",
    "ranking_formula": "FinalScore = R(s)^α · S(s)^β"
  }
}

