{
  "llm_reviews": {
    "test_coverage_review": {
      "trigger": "github_webhook",
      "criteria": "test_coverage_check_failure",
      "tools": [
        "fetch_github_diff",
        "fetch_github_pull_request",
        "fetch_code_coverage_report",
        "fetch_github_file_contents"
      ],
      "instructions": "You are an expert React and Typescript programmer. Using the test coverage reports and contents of source code and corresponding test files, suggest new test cases that would increase coverage of the source code.",
      "prompt_template": "You are performing a code review of ${diffSource}. The PR has failing test coverage checks for ${failingCoverage.join(', ')}. Use the diff and the code coverage report to identify the changes in the PR that are not covered by tests. For those changes, suggest test cases that should be added to the code. Use the existing test file as a reference when suggesting test cases. Do not suggest cases that are already covered by the existing tests.",
      "output": "Github Review with comments and suggestions for test cases",
      "evaluation": {
        "quantitative": "LLM evaluation framework with correctness score",
        "qualitative": "DX platform for developer feedback"
      }
    },
    "style_guide_enforcement": {
      "trigger": "github_webhook",
      "criteria": "code_style_check_failure",
      "tools": [
        "fetch_github_diff",
        "fetch_github_pull_request"
      ],
      "instructions": "You are an expert React and Typescript programmer. Using the code style guidelines, assess the quality of the title and description, and diagnose build failures.",
      "prompt_template": "You are performing a code review of ${diffSource}. The PR has failing style check. Use the diff to assess the quality of the title and description, and diagnose build failures. If applicable, issue auto-fix actions.",
      "output": "Github Review with comments and suggestions for style improvements",
      "evaluation": {
        "quantitative": "LLM evaluation framework with correctness score",
        "qualitative": "DX platform for developer feedback"
      }
    },
    "backward_compatibility_check": {
      "trigger": "github_webhook",
      "criteria": "backward_compatibility_check_failure",
      "tools": [
        "fetch_github_diff",
        "fetch_github_pull_request"
      ],
      "instructions": "You are an expert React and Typescript programmer. Using the code changes, detect backward-incompatible changes and suggest fixes.",
      "prompt_template": "You are performing a code review of ${diffSource}. The PR has failing backward compatibility check. Use the diff to detect backward-incompatible changes and suggest fixes.",
      "output": "Github Review with comments and suggestions for backward compatibility fixes",
      "evaluation": {
        "quantitative": "LLM evaluation framework with correctness score",
        "qualitative": "DX platform for developer feedback"
      }
    }
  },
