{
  "company": "Dropbox",
  "team": "Applied Machine Learning and Payments Engineering",
  "project": "Machine Learning for Payment Renewal Optimization",
  "overview": "Dropbox implemented a machine learning (ML) system to optimize the timing of payment renewals and retries during subscription failures. This system replaced a complex, rule-based approach with a more efficient, data-driven model that improved success rates and reduced collection time.",
  "key_components": {
    "model": {
      "type": "Gradient Boosted Ranking Model",
      "features": [
        "Payment failure types",
        "Account usage patterns",
        "Payment type characteristics"
      ],
      "training": "Built using customer data from 14 years of A/B testing",
      "prediction_window": "8-day window divided into 192 one-hour chunks",
      "optimization": "End-to-end optimization of renewal failure attempts"
    },
    "infrastructure": {
      "predict_service": "ML Platform's Predict Service for fast model serving",
      "latency": "Reduced from 2 minutes to under 300ms for 99% of predictions",
      "data_storage": "Edgestore for customer signals and model logs",
      "data_pipeline": "Airflow Jobs for daily data collection"
    },
    "monitoring": {
      "business_metrics": [
        "Invoice Approval Rate",
        "Attempt Success Rate"
      ],
      "model_metrics": [
        "Coverage",
        "Number of Predictions",
        "Prediction Latency"
      ],
      "infrastructure_metrics": [
        "Feature Data Freshness",
        "Predict Service Availability",
        "EdgeStore Availability"
      ],
      "tools": [
        "Grafana",
        "Vortex",
        "Superset"
      ]
    },
    "deployment": {
      "current_status": "Model for individual customers is in production; full renewal cycle model is in A/B testing",
      "future_goals": [
        "Global expansion to all customers",
        "Exploration of reinforcement learning and other advanced models"
      ]
    }
  },
  "impact": {
    "customer": "Improved renewal success rates and reduced collection time",
    "team": "Reduced complexity of billing system and improved maintainability",
    "business": "Increased revenue and improved user experience"
  },
  "challenges": {
    "initial": "High latency in model serving and complex system architecture",
    "solutions": [
