{
  "decision_support_system": {
    "description": "Lyft has developed a comprehensive decision support system based on causal forecasting, which integrates experimental and observational data to make informed business decisions. The system enables the evaluation of potential investments, such as improving modeling and forecasting, or developing more efficient coupons.",
    "components": {
      "model_declaration": {
        "description": "Models are declared using a flexible and modular approach, allowing for the creation of complex ModelCollections that can be treated as a single Model object. This enables hierarchical partitioning of modeling tasks.",
        "example": "A simple ETA model is declared with a loss function that measures agreement with experimentally determined values."
      },
      "loss_function": {
        "description": "The loss function is a weighted sum of terms that measure model fitness, causal validity, and regularization. This allows the model to align with experimental results and avoid overfitting.",
        "example": "si(.) measures how well a model agrees with experimentally determined values, such as the impact of driver hours on ETA."
      },
      "model_collection": {
        "description": "ModelCollections are collections of Models that form a DAG. This allows for the creation of complex, hierarchical models that can be optimized together.",
        "example": "A ModelCollection can include models for sessions, coupon-induced sessions, weather-induced sessions, and weather-adjusted sessions."
      },
      "optimization": {
        "description": "The system uses PyTorch's autograd functionality to efficiently calculate gradients and solve optimization problems, even with high-dimensional data. This enables the system to recommend the best decisions based on available information.",
        "example": "The system can determine optimal spending on driver incentives while respecting constraints such as maintaining low ETAs and profitability."
      },
      "evaluation": {
        "description": "The system evaluates model changes using causal validity and predictive accuracy. Causal validity compares predicted outcomes against experimental results, while predictive accuracy uses backtesting and metrics like MASE to assess out-of-sample performance.",
        "example": "The system calculates 'regret' to quantify whether a change is helping or hurting, based on the difference between predicted and actual outcomes."
      },
      "retrospective_analysis": {
        "description": "After decisions are made, the system can retrospectively evaluate forecasts and decisions by comparing them to an alternative where the future is known. This provides insights into the impact of forecast errors and guides future improvements.",
        "example": "The system shows how forecast errors in ETA and PT models led to fewer rides than expected, highlighting the cost of inaccurate forecasts."
      }
    },
    "application": {
      "example": "The system is applied to determine optimal spending on driver incentives, balancing the number of rides, ETAs, PrimeTime, and profitability. It provides contextual insights, such as the marginal cost of PrimeTime or the sensitivity of rides to demand forecasts.",
      "impact": "The system enables Lyft to make data-driven decisions, improve forecasting accuracy, and optimize resource allocation across different regions and time periods."
    }
  },
  "level_of_development": {
    "description": "The system is in a mature and operational state, with extensive use of the flexible model architecture and optimization techniques. It has been critical to the gradual and incremental development of Lyft's Causal Forecasting System."
  }
}

