{
  "ad_ranking_ml_engineering": {
    "overview": "The ad ranking machine learning (ML) engineering process at Snapchat is a complex, multi-stage workflow that involves offline experimentation, model development, deployment, and continuous monitoring. The system is designed to handle the massive scale of ad impressions and conversions, while also ensuring high-quality predictions and efficient resource utilization.",
    "key_components": {
      "features_and_signals": {
        "description": "Features and signals are critical inputs to the ad ranking models. These are derived from various data sources, including user behavior, ad content, and contextual information. The data is processed through custom data models and featurization technologies to extract meaningful signals that power the ranking models.",
        "challenges": [
          "New features require logging and forward filling before they can be used in models, which introduces delays.",
          "Feature engineering is complex due to the need to handle sparse data and ensure consistency across different data sources."
        ],
        "solutions": [
          "An in-house platform allows for declarative feature configuration and automates the end-to-end flow from feature generation to online serving.",
          "This platform enables quick offline experimentation without waiting for forward fill and unifies various feature pipelines."
        ]
      },
      "models": {
        "description": "The ad ranking models are built using state-of-the-art techniques, including multi-task learning, deep learning architectures, and advanced feature interaction layers. These models are trained on massive datasets and optimized for inference efficiency.",
        "innovations": [
          "Use of multi-task models like MMoE and PLE to predict multiple conversion events jointly.",
          "Application of high-order feature interaction layers like DCN and DCN v2.",
          "Splitting models into multiple towers for user and ad features to reduce inference latency."
        ],
        "metrics": [
          "Normalized Cross Entropy (NCE) as the primary offline metric for experimentation.",
          "AUC and calibration as secondary metrics to diagnose model behavior."
        ]
      },
      "training_and_deployment": {
        "description": "Training and deploying ad ranking models involves a distributed system that handles billions of rows of data. The system is optimized for speed, cost, and reliability, with support for large-scale distributed training and efficient model updates.",
        "techniques": [
          "Data parallelism with asynchronous gradient updates for fast training.",
          "Use of Google’s TPU technology for handling large models and reducing training time.",
          "Warm starting models from recent checkpoints and periodic batch updates using SGD optimization."
        ],
        "deployment": [
          "Models are continuously updated using new training data and deployed to the inference system for A/B testing.",
          "Automated calibration correction layers are applied to ensure model predictions stay close to realized conversions."
        ]
      },
      "workflow_management": {
        "description": "The ML engineering workflow is managed through an in-house platform that provides a declarative interface for defining experiments, data specifications, model architectures, and evaluation metrics. This platform enables efficient model development and deployment.",
        "features": [
          "Code-free YAML-based configuration for defining experiments.",
          "Translation of configurations into workflows and DAGs of standardized tasks.",
          "Support for custom tasks and docker-based deployment."
        ],
        "monitoring": [
          "Automated model updates and evaluation based on new data batches.",
          "Export of models to the inference system for online deployment after passing baseline metrics.",
          "On-call alerts for model failures or score drift."
        ]
      },
      "online_experimentation_and_monitoring": {
        "description": "Online experimentation and monitoring are essential for evaluating the business impact of changes to the ad ranking models. A/B testing is used to measure the effect of new features or model updates on advertiser budgets and ad impressions.",
        "techniques": [
          "Budget-split A/B testing to mitigate bias in two-sided marketplaces.",
          "Splitting advertiser budgets into multiple parts and assigning Snapchatters to different splits to test changes without affecting overall budgets."
        ],
        "monitoring": [
          "Real-time monitoring of model predictions and performance metrics.",
          "Inference benchmarking to evaluate model performance and cost before deployment."
        ]
      }
    },
    "conclusion": "The ad ranking ML engineering process at Snapchat is a highly sophisticated system that balances the need for high-quality predictions with the challenges of scale, latency, and resource efficiency. The use of advanced ML techniques, distributed training, and automated workflows enables the continuous improvement and deployment of ad ranking models, ensuring that Snapchat can deliver personalized and effective advertising to its users."
  }
}

