{
  "subject_line_generator": {
    "description": "A system that generates a single subject line for each post using OpenAI API without fine-tuning. The generator extracts the most interesting part of the post without making any changes, which helps maintain authenticity and avoid hallucinations.",
    "training": "No fine-tuning was applied to the generator. The prompt was engineered to extract the most interesting part of the post without rewriting it.",
    "results": "Prompt engineering improved performance by 3% compared to rewriting the subject line from scratch."
  },
  "reward_model": {
    "description": "A fine-tuned OpenAI API model that predicts whether a subject line will generate more engagement than a user-generated subject line. It is trained using A/B test data from real user clicks.",
    "training": "The reward model was fine-tuned using ~50k examples, with 40% of examples favoring OpenAI API-generated subjects and 60% favoring user-generated ones.",
    "results": "The final model increased Weekly Active Users by 0.4% and Ads revenue by 1% compared to user-generated subjects."
  },
  "engineering_details": {
    "caching": "Caching was implemented to reduce computational cost by processing each post only once, reducing cost to 1/600.",
    "monitoring": "Daily monitoring of the reward model's predictive performance using next-day click data to ensure accuracy.",
    "fallback": "Retries with exponential backoffs and fallback to user-generated subjects in case of OpenAI API errors.",
    "output_length": "Post-processing was used to limit subject line length to 10 words."
  },
  "ab_tests": {
    "metrics": "Sessions were the primary metric, measuring unique user visits within a timeframe.",
    "results": "Prompt engineering had a ceiling, while the reward model was the key factor in improving sessions. The final model achieved a 1% lift in sessions."
  },
  "future_work": {
    "fine_tuning_generator": "Fine-tuning the subject line generator using the reward model's identified most engaging titles.",
    "daily_rescoring": "Rescoring the same post daily to adapt to changing user preferences.",
    "personalization": "Adding personalization without significantly increasing computational costs."
  },
  "deployment": {
    "scope": "The system is deployed for all posts, generating a single subject line per post without personalization.",
    "cost": "The system is optimized for cost efficiency, with caching and limited API usage."
  },
  "impact": {
    "engagement": "The system improved user engagement by generating more effective subject lines than user-generated ones.",
    "revenue": "The final model increased Ads revenue by 1%."
  },
  "key_innovation": {
    "description": "Combining prompt engineering with a reward model to create a system that generates more engaging subject lines than user-generated ones.",
    "method": "The system uses a two-model approach: a subject line generator and a reward model that selects the most engaging subject line."
  },
  "challenges": {
    "training_data": "Collecting training data was challenging due to the lack of clear rules for what makes a subject line more engaging.",
    "prompt_optimization": "Finding the optimal prompt was an elusive task due to the vast space of potential prompts."
  },
  "conclusion": {
    "summary": "The system successfully improved user engagement by generating more effective subject lines than user-generated ones, with measurable increases in sessions and revenue.",
    "future": "Future work includes fine-tuning the generator, daily rescoring, and adding personalization."
  }
}

