{
  "content_ranking": {
    "heuristic_approach": {
      "factors": ["popularity", "share_of_registrations", "diversity"],
      "description": "A simple, fixed-weighting approach to select artists for campaigns based on popularity, share of registrations, and diversity. This allowed for a controlled exploration of a diverse pool of ads and artists."
    },
    "ml_approach": {
      "framework": "XGBoost",
      "features_used": [
        "campaign_market",
        "ad_creative_dimension",
        "operating_system",
        "template_theme",
        "template_variation",
        "artist_metadata"
      ],
      "target_variables": {
        "free_tier": {
          "reg_percentage": "Percentage of Spotify user registrations that the ranked artist will contribute to",
          "relative_cpr_ratio": "Ratio/share of the ranked artist in the overall CPR of a marketing campaign"
        },
        "premium_tier": {
          "sub_percentage": "Percentage of Spotify premium user subscriptions that the ranked artist will contribute to",
          "relative_cps_ratio": "Ratio/share of the ranked artist in the overall cost per subscription (CPS) of a marketing campaign"
        }
      },
      "results": {
        "ml_model_performance": {
          "cpr_reduction": "4% and 14% cheaper CPR than the heuristic model in two regions",
          "ctr_improvement": "11% to 12% higher click-through rate (CTR) due to richer training data"
        },
        "productionization": "The ML model was productionized to handle content ranking across all active regions where marketing campaigns were run."
      }
    }
  },
  "technical_challenges": {
    "challenge_1": {
      "description": "Orchestrating the generation of assets. Moving from Java templates to After Effects turned asset generation from something that could be done inline in an API call to something that needed rendering asynchronously. Scaling the render workers up and down in response to the volume of assets to be generated was also a challenge.",
      "takeaway": "Changes affecting the architecture can and will happen. Systems are initially designed with certain assumptions based on the information we have at the time. When new information inevitably comes along, it’s a good idea to assess how to incorporate the new requirements into the design as nonintrusively as possible and to move incrementally toward that. Systems built with modular components can make things easier, though it will never be possible to predict all the eventualities that can put pressure on the design."
    },
    "challenge_2": {
      "description": "Dependency on ad platform APIs for ingesting ad performance metrics. To feed the ML content ranking model with good-quality training data, the data pipelines have to fetch ad performance metrics from platform APIs on a daily basis. If there’s an issue retrieving data from these platform APIs, our ranking flows might break, or ultimately suggest content that is not ideal.",
      "example": "In a couple of instances, a Facebook API outage caused disruptions in our data pipelines, which resulted in the ML model not being able to train and churn out content rankings until Facebook’s marketing API was back to normal.",
      "takeaway": "Always find a backup solution when external dependencies break. It’s important to have a backup solution in case of an unforeseen situation, especially when critical systems rely on external APIs."
    }
  },
  "key_takeaways": {
    "architecture_evolution": "Systems should be designed with modularity in mind to allow for incremental changes and adaptations as new requirements emerge.",
    "backup_solutions": "Critical systems that rely on external APIs should have backup solutions in place to ensure continuity in case of outages or disruptions.",
    "ml_over_heuristics": "Machine learning models can outperform heuristic-based approaches when trained on rich, diverse data and when the problem space is complex and large-scale."
  }
}

