{
  "skill_extraction": {
    "description": "LinkedIn employs a comprehensive skill extraction system to identify and map relevant skills from various content types, including job postings, member profiles, and feeds. This system is critical for building a member-skill graph that enables deeper understanding of members and customers on the platform.",
    "components": {
      "skill_segmentation": {
        "description": "Before extracting any skill, the raw input is parsed into a well-formed structure. For example, a job posting may have sections for 'company description,' 'responsibilities,' 'benefits,' and 'qualifications.' Skills tagged in the 'qualifications' section are more likely to be important than those in the 'company description' section.",
        "techniques": [
          "Parsing structured content (e.g., job postings, resumes)",
          "Section-based prioritization of skill importance"
        ]
      },
      "skill_tagging": {
        "description": "Once the raw input is parsed, a skill tagger identifies mentions of skills in the text. This tagger can perform both token-based and semantic-based skill matches.",
        "techniques": [
          "Token-based skill matching using a trie-based tagger",
          "Semantic-based skill matching using a two-tower model with Multilingual BERT"
        ]
      },
      "skill_expansion": {
        "description": "Starting from the set of tagged skills, the system expands the skills further to bring in relevant skills to increase the chance of skill matches. This expansion relies on the Skills Graph to query for related skills.",
        "techniques": [
          "Querying the Skills Graph for related skills (parent, child, sibling skills)",
          "Expanding skill sets to improve match accuracy"
        ]
      },
      "multitask_cross_domain_skill_scoring": {
        "description": "After discovering relevant skill candidates, a multitask scoring model identifies the best matches between content and skills. This model includes a shared module and domain-specific modules.",
        "techniques": [
          "Shared module with Contextual Text Encoder and Contextual Entity Encoder",
          "Domain-specific model towers for different skill verticals (e.g., job postings, member profiles, feeds)"
        ]
      },
      "model_serving_at_scale": {
        "description": "Extracted and normalized skills must be served at scale to be used by LinkedIn members, products, and AI systems. This requires robust infrastructure and optimization techniques.",
        "techniques": [
          "Knowledge Distillation to reduce model size by 80% without compromising performance",
          "Hybrid offline/nearline serving architecture for cost and latency optimization"
        ]
      },
      "product_driven_model_improvement": {
        "description": "Feedback loops are built directly into the system to improve the quality of skill extraction and mapping. These feedback mechanisms come from recruiters, job seekers, and members.",
        "techniques": [
          "Recruiter feedback on suggested skills during job posting",
          "Seeker feedback on skill overlap between profile and job",
          "Member profile feedback through LinkedIn Skill Assessments (SAs)"
        ]
      }
    },
    "applications": {
      "career_relevant_skills": {
        "description": "Skill extraction is used to identify the most important and relevant skills for a member's career. This data is used to recommend relevant job opportunities to members and provide better candidate suggestions to recruiters.",
        "techniques": [
          "Contextual skill data collection",
          "Job application data analysis for career relevance"
        ]
      },
      "skill_proficiency_estimation": {
        "description": "LinkedIn estimates a member's proficiency in a skill after the skill is extracted. This is done using a multitask learning framework with an uncertainty weighting scheme.",
        "techniques": [
          "Multitask learning with uncertainty weighting",
          "Enriching the skills graph with proficiency dimensions"
        ]
      },
      "job_important_skills": {
        "description": "Building an accurate and comprehensive skill profile for jobs is the foundation of LinkedIn's skills-first initiatives. This helps recruiters and members understand the skills that are most important for a given job.",
        "techniques": [
          "Skill profiling for job relevance",
          "Integration with job application data"
        ]
      }
    }
  },
  "conclusion": "LinkedIn's skill extraction system is a sophisticated and scalable solution that leverages advanced NLP techniques, including token-based and semantic-based skill matching, multitask learning, and model compression. The system is continuously improved through feedback loops and is applied across various products and services to enhance the member experience and improve job matching."
}

