      ],
      "implementation_details": {
        "masking": {
          "purpose": "To prevent the model from selecting incorrect or inefficient actions by masking token logits during decoding.",
          "implementation": "Using context-aware state machines and prefill techniques to constrain the action space without modifying tool definitions.",
          "modes_of_function_calling": [
            "Auto",
            "Required",
            "Specified"
          ]
        },
        "file_system_as_context": {
          "purpose": "To provide an unlimited, persistent, and operable memory system for the agent.",
          "implementation": "Storing and retrieving information from the file system rather than the model's context window.",
          "restoration_strategies": [
            "Preserving URLs for web pages",
            "Keeping document paths in the sandbox"
          ]
        },
        "attention_manipulation": {
          "purpose": "To keep the model focused on the task objective by reciting the todo list into the context.",
          "implementation": "Updating a todo.md file step-by-step to push the global plan into the model's recent attention span."
        },
        "error_retention": {
          "purpose": "To allow the model to learn from mistakes by retaining failed actions and observations in the context.",
          "implementation": "Leaving error traces in the context to update the model's internal beliefs and reduce the chance of repeating the same mistake."
        },
        "diversity_in_context": {
          "purpose": "To prevent the model from falling into repetitive patterns by introducing structured variation in the context.",
          "implementation": "Using different serialization templates, alternate phrasing, and minor noise in order or formatting."
        }
      },
      "impact_on_agent_behavior": {
        "stability": "Ensures the agent loop remains stable even under complex or long-running tasks.",
        "recovery": "Improves error recovery by allowing the model to learn from past mistakes.",
        "adaptability": "Enhances the agent's ability to adapt to new or changing environments by maintaining a diverse and informative context."
      }
    },
    "conclusion": {
      "summary": "Context engineering is a critical component of building effective agentic systems. By carefully shaping the context, developers can influence how the agent behaves, how it recovers from errors, and how far it can scale.",
