{
  "status": "success",
  "data": {
    "llm_patterns_used": [
      {
        "pattern": "In-context learning (ICL)",
        "description": "A pre-trained LLM is provided with a prompt or 'context' to guide its answers for a specific task. This process does not involve any additional training, and the same model can be reused for different tasks with different prompts. It is very fast to set up and iterate, cheap, and versatile as it can be used in several tasks. Internally, this remains one of the most popular ways of prototyping and evaluating usage of LLM in a product."
      },
      {
        "pattern": "Retrieval Augmented Generation (RAG)",
        "description": "LLM generated responses are grounded with facts fetched from external sources (knowledge bases such as a corpus of documents, catalog of products, etc). Making the generation and retrieval components work seamlessly in real-time is nontrivial, leading to potential bottlenecks and errors."
      },
      {
        "pattern": "Supervised fine-tuning (SFT)",
        "description": "Further training an existing base LLM on small datasets to improve performance on a specific domain or task. A fine-tuned model on a high quality domain dataset often surpasses the base LLM performance."
      },
      {
        "pattern": "Continued pre-training (CPT)",
        "description": "Further pre-training of an existing base LLM on sizable datasets to improve generalized understanding of the model without focusing on any specific task. This is resource intensive but often produces the best results on downstream tasks like attribute extraction."
      }
    ],
    "llm_development_lifecycle": {
      "exploration_phase": {
        "focus": [
          "Model architecture",
          "Model size — Return on Investment (ROI) of using larger sizes for example 70B+ variant vs < 10B parameter variant",
          "Prompt templates — Changing prompt templates can change model outputs and therefore the performance"
        ],
        "tools": [
          "Apache Zeppelin [2.1] notebooks",
          "Spark [2.2] on Kubernetes",
          "GPU (or multi-GPU) containerized Jupyter notebooks [2.3]"
        ]
      },
      "model_training": {
        "process": "Based on the shortlist, developers use fine-tuning or pre-training from scratch depending on the compute budget, dataset size and comparing model performance. Based on model performance on the application, developers finalize the model to put into production. There isn’t any process difference from the non-LLM model development lifecycle here. We will call it the source LLM model.",
        "tools": [
          "Polyaxon [2.4] for managing ML training lifecycle on Kubernetes",
          "PytorchJob [2.5] for distributed training operator for Pytorch"
        ]
      },
      "path_to_production": {
        "methods": [
          "Distillation: Distill a smaller model from the trained source LLM. The smaller model is used in real-time inference.",
          "Embedding: Embeddings can be exported from the LLMs and used in smaller models. We see this pattern being used in ranking problems."
        ],
        "tools": [
          "Batch and nearline inference on GPUs is the most popular way to extract predictions from the source LLMs at scale and then use it for distillation or as embeddings.",
          "Ray + vLLM [2.6, 2.7] to write inference pipelines requiring both CPU and GPU processing."
        ]
      }
    },
    "key_challenges": [
      "Resource efficiency and management largely due to supply shortage and high cost of GPUs.",
      "Capabilities of training and serving large models. Our training stack was not equipped for distributed training (especially model parallel). Before LLMs, our serving was entirely on CPUs which are too slow for the multi-billion parameter models."
    ],
    "key_learnings": [
      "Choosing the Right Workhorse: Matching Appropriate GPU for the Workload",
      "Hybrid & Multi-Region AI Clusters",
      "Embracing the Open Source - Frameworks & Tools"
    ],
    "gpu_strategy": {
      "training": {
        "large_models": "A100–80 GB version for models with more than 1 billion parameters in mixed precision mode.",
        "lightweight_training": "A10G-24 [3.3] GB devices for testing and lightweight training purposes."
      },
      "inference": {
        "realtime": "Nvidia Triton [2.9] on AWS EKS for realtime inference.",
        "batch": "Ray + vLLM for managing heterogeneous computing at scale.",
        "nearline": "Combines the efficiency of batch inference (using small batches) and the responsiveness of being near real-time inference (within a certain time of event occurrence)."
      }
    },
    "infrastructure": {
      "cloud": "Leveraging cloud service clusters across various regions (Asia-Pacific & US) for faster access to GPUs.",
      "on-prem": "Building an on-prem cluster to provision a significant portion of our computer, especially the higher-end Nvidia GPUs (such as A100/H100)."
    },
    "tools_used": [
      "Apache Zeppelin [2.1]",
      "Spark [2.2]",
      "Jupyter notebooks [2.3]",
      "Polyaxon [2.4]",
      "PytorchJob [2.5]",
      "Ray + vLLM [2.6, 2.7]",
      "Nvidia Triton [2.9]"
    ],
    "model_architectures": {
      "language_models": [
        "Qwen [1.1]",
        "LLAMA [1.2]",
        "T5 [1.3]",
        "Phi[1.4]",
        "Polyglot [1.5]"
      ],
      "image-text_models": [
        "CLIP [1.6] (Contrastive Language Image Pretraining)",
        "TrOCR [1.7] (Transformer based OCR)"
      ]
    },
    "model_sizes": {
      "preferred_range": "3B to 20B parameters",
      "reason": "Striking a good balance between resource and compute efficiency and quality."
    }
  },
  "message": "The article provides a comprehensive overview of LLM development patterns, lifecycle, challenges, and infrastructure strategies at Coupang. It highlights the use of various LLM patterns, model architectures, and tools to support the development and deployment of large language models."
}

