{
  "sales_forecasting": {
    "status": "active",
    "description": "Mercado Libre has implemented a Global Time Series (GTS) model for sales forecasting, which uses historical sales data, customer interaction, and price elasticity as features. The model is trained to predict future sales for items that have had at least one unit sold in the forecast horizon.",
    "performance_metric": "Mean Absolute Error (MAE)",
    "key_findings": [
      "The model outperforms the mean forecast baseline, with an average MAE of around 10 units across the forecast horizon.",
      "The model captures decreasing sales trends associated with lower stock levels.",
      "It is effective at identifying items that have run out of stock and are unlikely to have sales in the forecast period."
    ],
    "improvement_direction": "The team is exploring probabilistic forecasting models using Monte Carlo Dropout to better capture forecast uncertainty and improve replenishment decisions."
  },
  "demand_forecasting": {
    "status": "active",
    "description": "A separate GTS model is used for demand forecasting, which predicts potential sales if items had sufficient stock. This model includes price variation as a feature to account for past discounts.",
    "performance_metric": "Mean Absolute Error (MAE)",
    "key_findings": [
      "The demand model predicts a potential sales recovery for items that may have run out of stock.",
      "It exhibits increasing error across the forecast horizon, which is expected due to the nature of the model's training objective.",
      "The model is less accurate for items that had no sales in the forecast period, as it assumes potential sales recovery."
    ],
    "improvement_direction": "The team is working on improving the model's accuracy for items with no sales and exploring probabilistic forecasting to better capture uncertainty."
  },
  "combined_model": {
    "status": "active",
    "description": "The sales and demand models are used together to provide a more comprehensive view of inventory and replenishment decisions. The sales model predicts actual sales, while the demand model predicts potential sales if stock were available.",
    "key_advantages": [
      "The combination of both models provides a more nuanced understanding of inventory behavior.",
      "The sales model helps with inventory management and restocking decisions.",
      "The demand model helps with planning for potential sales and identifying items that may need restocking."
    ],
    "improvement_direction": "The team is working on integrating uncertainty into the forecasting process to improve decision-making for replenishment and inventory planning."
  },
  "future_work": {
    "probabilistic_forecasting": {
      "status": "in_progress",
      "description": "The team is exploring probabilistic forecasting models using Monte Carlo Dropout to better capture forecast uncertainty and improve replenishment decisions."
    },
    "continuous_improvement": {
      "status": "ongoing",
      "description": "Mercado Libre is in a state of continuous improvement, with the team always looking for opportunities to refine and enhance their forecasting models."
    }
  },
  "references": [
    "Conrad, S. A. (1976). Sales data and the estimation of demand. Journal of the Operational Research Society, 27(1), 123–127.",
    "Hewamalage, H., Bergmeir, C., & Bandara, K. (2020). Global models for time series forecasting: A simulation study. arXiv preprint arXiv:2012.12485.",
    "Montero-Manso, P., & Hyndman, R. J. (2021). Principles and algorithms for forecasting groups of time series: Locality and globality. International Journal of Forecasting."
  ]
}

