{
  "semantic_label_representation": {
    "description": "A method to improve the accuracy and semantic similarity of product categorization by incorporating semantic relationships between labels into the training process.",
    "key_components": [
      {
        "name": "Semantic Label Smoothing",
        "description": "Softening label representations using semantic neighbors (top 20) to encode semantic relationships, improving both accuracy and semantic similarity of predictions."
      },
      {
        "name": "Multi-Label Classification",
        "description": "Replacing multi-class classification with multi-label tasks to preserve semantic relationships between closely related labels."
      },
      {
        "name": "Focal Loss",
        "description": "Used to address class imbalance in the training data, improving model performance on rare categories."
      },
      {
        "name": "Curriculum Learning",
        "description": "Used in combination with semantic label smoothing to gradually harden targets during training, improving model robustness."
      }
    ],
    "application": {
      "domain": "E-commerce",
      "task": "Multimodal Product Categorization",
      "inputs": [
        "Product images",
        "Product titles"
      ],
      "outputs": [
        "Product category labels"
      ],
      "model": {
        "base_model": "CLIP encoders (OpenAI)",
        "finetuning_layer": "Multilayer Perceptron (MLP)",
        "loss_functions": [
          "Focal Loss",
          "KL Divergence (between logits and soft targets)"
        ]
      }
    },
    "results": {
      "top_1_accuracy": {
        "baseline": "Not explicitly stated",
        "semantic_aware_3": "Second-best",
        "semantic_aware_4": "Best"
      },
      "top_5_accuracy": {
        "baseline": "Not explicitly stated",
        "semantic_aware_4": "Best",
        "semantic_aware_5": "Best with curriculum learning"
      },
      "semantic_similarity": {
        "baseline": "Low",
        "semantic_aware_4": "Best",
        "semantic_aware_3": "Good approximation"
      },
      "metrics": {
        "top_predictions_in_close_range": {
          "baseline": "1.55%",
          "semantic_aware_4": "4.05%",
          "semantic_aware_3": "Good approximation"
        }
      }
    },
    "recommendations": [
      "Use semantic-aware label smoothing (approach #4) for the best balance between accuracy and semantic similarity.",
      "Use semantic-aware approach #3 as a practical approximation when quantifying semantic relationships is challenging.",
      "Combine semantic label smoothing with curriculum learning for improved model robustness."
    ],
    "limitations": [
      "Constructing precise binary codes for feature similarities is impractical for large-scale product categorization.",
      "Semantic relationships may be ambiguous in taxonomies, requiring fallback to qualitative knowledge."
    ]
  }
}

