{
  "error_classification_service": {
    "name": "Pensive",
    "components": [
      {
        "name": "Log Collector",
        "description": "Pulls logs from different platform layers for error classification (e.g., scheduler, job orchestrator, compute clusters)."
      },
      {
        "name": "Rule Execution Engine",
        "description": "Matches collected logs against predefined rules. A rule includes error name, source, log, summary, restartability, and regex for error identification."
      },
      {
        "name": "Result Finalizer",
        "description": "Finalizes error classification based on matched rules. If no rules match, the error is considered unclassified."
      }
    ],
    "challenges": [
      {
        "type": "Memory Configuration Errors",
        "description": "Rules-based classifier struggles with misconfigured memory settings, which can lead to OOM errors or wasted resources. Requires manual intervention and expertise."
      },
      {
        "type": "Unclassified Errors",
        "description": "Existing rules may become invalid due to platform migrations or application diversity. Adding new rules requires engineering effort and depends on deployment cycles."
      }
    ]
  },
  "ml_service": {
    "name": "Nightingale",
    "components": [
      {
        "name": "Prediction Model",
        "description": "Estimates retry success probability and retry cost based on job properties. Retrained daily and used by the optimizer to evaluate candidate configurations."
      },
      {
        "name": "Optimizer",
        "description": "Explores Spark configuration parameter space to recommend configurations that minimize retry failure probability and cost. Uses Bayesian Optimization via Meta’s Ax library."
      }
    ],
    "training": {
      "data": "Job logs with retry success outcomes and execution costs.",
      "features": [
        "Spark execution plan",
        "User who ran the job",
        "Spark configuration parameters",
        "Other job properties"
      ],
      "processing": [
        "Feature hashing for non-numeric values",
        "Embedding creation for lower dimensionality",
        "Concatenation with normalized numeric values"
      ]
    },
    "inference": {
      "service": "Metaflow Hosting",
      "description": "Stores and serves new model versions. Optimizer calls prediction function for incoming configuration recommendation requests."
    }
  },
  "configuration_service": {
    "name": "ConfigService",
    "description": "Stores and applies recommended configurations as JSON patches. Mutates original configurations based on job-specific scope."
  },
  "scheduler": {
    "name": "Scheduler",
    "description": "Schedules jobs (using Netflix Maestro). Calls Pensive for error classification and ConfigService for recommended configurations upon job failure."
  },
  "service_integrations": {
    "Nightingale": "Generates retry recommendations based on ML model.",
    "ConfigService": "Stores and applies recommended configurations as JSON patches.",
    "Pensive": "Classifies errors using rule-based classifier and calls Nightingale for recommendations.",
    "Scheduler": "Schedules jobs and uses Pensive and ConfigService for error classification and configuration application."
  },
  "sequence_of_service_calls": [
    {
      "step": 1,
      "description": "Upon job failure, Scheduler calls Pensive to get error classification."
    },
    {
      "step": 2,
      "description": "Pensive classifies the error using the rule-based classifier. If it's a memory configuration or unclassified error, it calls Nightingale for recommendations."
    },
    {
      "step": 3,
      "description": "Pensive updates the error classification result and saves recommended configurations to ConfigService."
    },
    {
      "step": 4,
      "description": "Scheduler determines whether to restart the job based on the error classification result."
    },
    {
      "step": 5,
      "description": "Scheduler calls ConfigService to get the recommended configuration and retries the job with the new configuration."
    }
  ],
  "key_metrics": {
    "memory_configuration_errors_per_month": 600,
    "unclassified_errors_percentage": 50,
    "cost_reduction_percentage": 50
  },
  "potential_for_improvement": {
    "description": "Great potential for further improvement through model tuning and additional rule additions."
  }
}

