{
  "ai_modeling": {
    "model_type": "Hierarchical Machine Learning Model",
    "components": [
      {
        "name": "General Availability (G)",
        "description": "Captures long-term availability patterns over 7–180 days, addressing data sparsity by using aggregated historical data.",
        "input": "Historical purchase data, regional trends, product categories",
        "output": "Baseline availability probability"
      },
      {
        "name": "Trending (T)",
        "description": "Quantifies short-term deviations from the general baseline, capturing recent events like supply chain disruptions or demand surges.",
        "input": "General availability scores, recent purchase data, event-based features",
        "output": "Deviation from baseline availability"
      },
      {
        "name": "Real-Time (R)",
        "description": "Responds to the most recent observations, enabling timely updates to availability status based on streaming data.",
        "input": "Latest shopper reports, retailer inventory levels, time since last observation",
        "output": "Short-term availability prediction"
      }
    ],
    "architecture": "G-T-R hierarchical structure",
    "training": {
      "offline": "XGBoost model trained on historical data with general scores as input",
      "online": "Real-time inference using streaming data and latest observations"
    },
    "interpretability": {
      "enabled": true,
      "methods": [
        "Comparing trending output against general scores",
        "Analyzing contribution of each component to final prediction"
      ]
    }
  },
  "system_engineering": {
    "infrastructure": {
      "name": "Griffin",
      "description": "Latest MLOps tool suite developed by Instacart Machine Learning Infra team",
      "features": [
        "Real-time data streaming pipeline",
        "Feature store integration",
        "Model versioning and API support"
      ]
    },
    "pipeline": {
      "structure": "Stratified scoring based on item frequency",
      "groups": [
        {
          "name": "Head items",
          "description": "Frequent items with latest signals within 10 hours",
          "scoring_frequency": "Hourly (trending) + Daily (general)"
        },
        {
          "name": "Torso items",
          "description": "Moderately frequent items with signals within a month",
          "scoring_frequency": "Daily (general and trending)"
        },
        {
          "name": "Tail items",
          "description": "Rarely purchased items with signals over 180 days",
          "scoring_frequency": "Daily (general)"
        }
      ],
      "cost_reduction": "80% reduction in computation costs due to less frequent scoring for torso and tail items"
    },
    "api": {
      "features": [
        "Support for multiple model versions",
        "Context-aware scoring (e.g., logistics vs. customer cart building)",
        "Different scores for same item based on use case"
      ]
    }
  },
  "business_impact": {
