{
  "model_development": {
    "objective": "Reduce the gap between stated delivery days and actual delivery times by about half while maintaining a comparable delivery rate to the old model.",
    "approach": "Shifted from a fragmented, multi-step prediction approach to a holistic, end-to-end machine learning model using quantile regression with catboost.",
    "key_features": [
      "Average supplier lead time",
      "Physical distance between supplier warehouse and customer",
      "Order date (time of day, day of week)",
      "Delivery impediments (e.g., carrier not delivering on Sundays)",
      "Supplier variability in lead times",
      "Temporal features to mimic cyclical dependencies"
    ],
    "technical_challenges": [
      "Optimizing feature look-ups and network round-trips to meet strict latency constraints (< 40ms for 99.99% of requests)",
      "Implementing a custom loss function in C++ for catboost to handle different delivery speed groups",
      "Balancing reactivity and stability in model training by using recency weighting and historical holiday data"
    ],
    "outcomes": {
      "performance": "Reduced the gap between stated and actual delivery days by about half.",
      "business_impact": "Increased conversion rate and revenue, with the model's cost being offset by the gains.",
      "technical_success": "Achieved high reliability and performance under tight latency constraints."
    },
    "learnings": [
      "A holistic, end-to-end approach is more suitable for machine learning than fragmented, multi-step models.",
      "Understanding the supply chain in detail is critical for feature engineering and model success.",
      "Highly relevant features improve learning speed and model performance, even with standard ML techniques.",
      "Effective communication with stakeholders and engineering partners is essential for turning academic models into production systems."
    ],
    "future_directions": [
      "Expanding the model to the European market and orders from Wayfair-owned warehouses.",
      "Exploring transformer-based architectures for improved accuracy, inspired by Ubers drivetime estimation.",
      "Continuing to refine the model with additional machine learning methods."
    ]
  },
  "technical_details": {
    "model_type": "Quantile regression using catboost",
    "training_data": {
      "recency_weighting": true,
      "holiday_data": true,
      "feature_engineering": true
    },
    "latency_constraints": {
      "target": "Less than 40ms for 99.99% of requests",
      "achieved": true
    },
    "custom_loss_function": {
      "implemented_in": "C++",
      "purpose": "Handle different delivery speed groups with separate quantiles"
    },
    "feature_engineering": {
      "key_insights": [
        "Distance between customer and supplier is critical for delivery time estimation.",
        "Temporal features help capture cyclical dependencies (e.g., holidays, weekends)."
      ],
      "optimization": "Features were prepared to be highly relevant, improving learning speed and performance."
    }
  },
