{
  "system_prompt": "You are a highly capable AI assistant that can understand and respond to complex queries. You are trained to provide accurate, detailed, and well-structured responses. You should maintain a professional tone and ensure clarity in your communication.",
  "response": {
    "summary": "Strategy Factory is an advanced rule generation and optimization system developed by Binance to enhance risk control across various domains such as login protection, KYC, deposits, and withdrawals. It leverages techniques like Split, FIT, Global Gain, and Split Constraints to create business-aware, interpretable rules that improve precision, recall, and operational impact. The system is designed to be flexible, scalable, and user-friendly, with a conversational AI agent in development to further reduce onboarding friction.",
    "key_features": [
      "Split: A single-path rule generation technique that builds rules incrementally.",
      "FIT: A module that loops through Split to generate diverse, complementary rule sets.",
      "Global Gain: A business-aware utility function that optimizes rules for real-world outcomes like precision and recall.",
      "Split Constraints: Allows analysts to inject domain knowledge and business requirements into the rule generation process.",
      "Squeeze and Grow: Tools for refining and enhancing existing rules to better fit shifting business needs.",
      "Airflow-based pipeline: A flexible, end-to-end system for rule optimization and deployment."
    ],
    "adoption_highlights": [
      "Reduced investigation times by 25% in login protection against account takeovers.",
      "SF-generated rules now represent over 25% of all risk detections in withdrawal protection for scam prevention.",
      "Improved coverage and precision compared to existing rules, with a 60% increase in the system’s lifting standard."
    ],
    "roadmap": [
      "Development of a conversational AI agent UI to make Strategy Factory more accessible to teams with varying levels of technical expertise.",
      "Further integration with existing risk control systems to enhance automation and scalability.",
      "Exploration of advanced machine learning techniques to improve rule generation and adaptability to new data patterns."
    ],
    "example": {
      "input": {
        "data": [
          {"ID": 1, "Fruit Type": "Apple", "Color": "Red", "Sweetness": 0.9, "Size": 7, "Positive": 1, "Negative": 0, "Target": 0},
          {"ID": 2, "Fruit Type": "Banana", "Color": "Yellow", "Sweetness": 0.85, "Size": 15, "Positive": 1, "Negative": 0, "Target": 0},
          {"ID": 3, "Fruit Type": "Lemon", "Color": "Yellow", "Sweetness": 0.2, "Size": 6, "Positive": 0, "Negative": 1, "Target": 0},
          {"ID": 4, "Fruit Type": "Grape", "Color": "Purple", "Sweetness": 0.95, "Size": 1.5, "Positive": 1, "Negative": 0, "Target": 1},
          {"ID": 5, "Fruit Type": "Pear", "Color": "Green", "Sweetness": 0.7, "Size": 8, "Positive": 0, "Negative": 1, "Target": 0},
          {"ID": 6, "Fruit Type": "Strawberry", "Color": "Red", "Sweetness": 0.8, "Size": 3, "Positive": 1, "Negative": 0, "Target": 1},
          {"ID": 7, "Fruit Type": "Apple", "Color": "Green", "Sweetness": 0.88, "Size": 7, "Positive": 1, "Negative": 0, "Target": 0},
          {"ID": 8, "Fruit Type": "Lemon", "Color": "Yellow", "Sweetness": 0.25, "Size": 5.5, "Positive": 0, "Negative": 1, "Target": 0},
          {"ID": 9, "Fruit Type": "Grape", "Color": "Purple", "Sweetness": 0.92, "Size": 2, "Positive": 1, "Negative": 0, "Target": 1},
          {"ID": 10, "Fruit Type": "Banana", "Color": "Yellow", "Sweetness": 0.75, "Size": 14, "Positive": 1, "Negative": 0, "Target": 0}
        ],
        "requirement": "Recall = 100%",
        "original_rule": "Color == 'Red' (Recall = 1/3 ≈ 33%, Precision = 1/2 = 50%)"
      },
      "output": {
        "optimized_rule": "(Color IN ['Red', 'Purple']) AND (Sweetness > 0.75)",
        "performance": {
          "recall": "100%",
          "precision": "75%"
        },
        "interpretation": "If it’s red or purple and sweet enough, it’s probably what we’re looking for. It caught all 3 targets (100% recall), and 3 out of 4 picks were correct (75% precision)."
      }
    },
    "conclusion": "Strategy Factory represents a significant advancement in rule-based risk control systems, combining statistical rigor with business insight. Its ability to generate, optimize, and refine rules in real-world contexts has made it an essential tool for Binance’s risk management operations, with clear benefits in terms of efficiency, accuracy, and adaptability."
  }
}

