  },
  "suggestion_repository": {
    "function": "Stores all suggestions received from the backend",
    "updates": "When a suggestion is applied or becomes irrelevant, it is removed from the repository",
    "notification": "Notifies the Delta Manager and Highlights Manager of changes"
  },
  "highlights_manager": {
    "function": "Highlights mistakes in the text based on suggestions",
    "updates": "Re-renders highlights when the text changes or suggestions are applied"
  },
  "delta_composition": {
    "function": "Combines multiple suggestion Deltas into a single Delta for bulk application",
    "example": "const composedDelta = delta1.compose(delta2).compose(delta3)...",
    "benefit": "Reduces UI freezing by performing the update in a single step"
  },
  "rebase_procedure": {
    "function": "Updates suggestion Deltas to reflect changes in the text",
    "example": "When the text is edited, the suggestion Delta is rebased to point to the new target",
    "code": "const rebasedDelta = delta.rebase(editDelta)"
  },
  "bulk_suggestion_application": {
    "function": "Applies multiple suggestions at once by composing their Deltas",
    "challenge": "When applying multiple suggestions, each must be rebased as if the previous ones were already applied",
    "solution": "Iterate through each suggestion, rebase it, and compose it with the accumulated Delta"
  },
  "architecture_overview": {
    "components": [
      "Suggestions Repository",
      "Delta Manager",
      "Highlights Manager"
    ],
    "cycle": "When text changes, the system notifies all components, updates the repository, and re-renders highlights and cards"
  },
  "performance_optimization": {
    "issue": "Repeatedly updating the text Delta for each suggestion caused UI freezing",
    "solution": "Compose all suggestion Deltas into one, reducing the number of updates"
  },
  "user_experience": {
    "goal": "Ensure suggestions are applied instantly without freezing the UI",
    "result": "Bulk suggestion application is now fast and seamless"
  },
  "technical_insights": {
    "delta_operations": ["insert", "delete", "retain"],
    "rebase_algorithm": "Based on Quill's rebase algorithm",
    "composition": "Deltas are composed using the .compose() method"
  },
  "application_flow": {
    "step_1": "User accepts a suggestion",
    "step_2": "Suggestion state is updated from 'registered' to 'applied'",
    "step_3": "Text Delta is updated by composing with the suggestion Delta",
    "step_4": "UI is updated to reflect the new text and remove the suggestion card"
  },
  "key_concepts": {
    "delta": "A sequence of operations representing text changes",
    "rebase": "Updating a Delta to reflect changes in the text",
