{
  "system": "PYMK (People You May Know) recommendation system",
  "components": {
    "graph-based-cg": {
      "techniques": [
        "N-hop neighbor generation",
        "Personalized PageRank (PPR) algorithm"
      ],
      "description": "Generates candidates based on network proximity. N-hop neighbors are members within a certain number of connections from the viewer. PPR extends this by propagating influence through the network, even for members further away. PPR is personalized to the viewer, making it more effective for under-connected users."
    },
    "similarity-based-cg": {
      "techniques": [
        "Embedding-based retrieval (EBR)",
        "Two Tower Neural Network"
      ],
      "description": "Generates candidates based on profile, skill, and engagement similarities. Member embeddings are learned using a Two Tower Neural Network, and candidates are retrieved via nearest-neighbor search. The model is trained to pull embeddings of impressed candidates closer to the viewer's embedding."
    },
    "heuristics-based-cg": {
      "techniques": [
        "Simple filters for recent interactions",
        "Activity-based filtering"
      ],
      "description": "Generates candidates using simple rules, such as members who recently interacted with the viewer, clicked on their activity, or searched their profile. These are used to supplement other CG techniques."
    },
    "final-candidate-pool": {
      "description": "Aggregates top candidates from all CG techniques. Each candidate has a score (e.g., number of common connections for N-hop, PPR score, or embedding similarity). A 1-hot encoded feature indicates the CG technique used, which is used as a bias term in ranking."
    },
    "ranking": {
      "description": "The final candidate pool and scores are passed to a ranker to generate the final PYMK recommendations. The ranker uses the scores and CG technique features to prioritize candidates."
    },
    "evaluation": {
      "metrics": [
        "Recall@k",
        "Entropy over categorical attributes (e.g., country)"
      ],
      "description": "Recall@k is the primary metric for evaluating the effectiveness of CG. Entropy is used to measure diversity in the candidate pool. The distribution of CG sources is also analyzed to detect skew."
    },
    "future-considerations": {
      "points": [
        "Exploring GNN embeddings for graph-based CG",
        "Migrating parts of the system to near-realtime",
        "Exploring deep sequential learning for candidate generation"
      ],
      "description": "The team is continuously exploring ways to improve the CG system, including leveraging GNN embeddings, making parts of the system near-realtime, and using deep learning techniques."
    }
  },
  "impact": {
    "online": {
      "results": [
        "Increase in member engagement",
        "Improvement in retention for infrequent members"
      ],
      "description": "A/B tests showed that the CG techniques significantly improved engagement and retention. Frequent members saw increased engagement, while infrequent members saw improved retention."
    },
    "insights": {
      "key-ideas": [
        "Soft-confining in PPR for personalization",
        "Using impressions as positives in EBR to avoid favoring frequent members",
        "Nearest-neighbor negatives for generating hard negatives"
      ],
      "description": "The team shared insights on how to improve graph recommendation systems, including personalization techniques, bias mitigation, and generating hard negatives."
    }
  },
  "conclusion": {
    "statement": "Candidate generation is a critical component in determining the quality of a large-scale recommendation system. The techniques described here have been instrumental in improving engagement and retention."
  }
}

