{
  "etr_display": {
    "status": "live",
    "description": "The ETR (Estimated Time to Receive) is displayed on the Uber Driver app, providing drivers with an estimate of how long they will wait before being dispatched from the airport queue. This helps drivers plan their time more effectively and improves the overall efficiency of the airport pickup process.",
    "implementation": "The ETR is calculated using a modularized system that combines supply and demand models. The Venue Marker service interacts with the prediction endpoint to calculate the ETR prediction and pushes the driver inspection sheet to the driver app.",
    "modularization": "The system was deliberately modularized to mitigate risk with complexity, allowing for the reuse of individual elements in other Airport projects. This improves efficiency and aligns the technology underpinning multiple products."
  },
  "engineering_design": {
    "reusable_features": "The project resulted in reusable MA Palette Features, which include most near-real-time features and some batch-based features. These can be shared with many rider vertical ML use cases and BI analytics purposes.",
    "architectural_diagrams": {
      "etr_calculation": "Figure 3 shows the overall architecture for ETR calculation and EQL model, including how the venue marker service interacts with the prediction endpoint and pushes data to the driver app.",
      "demand_forecasting": "Figure 4 illustrates the demand forecasting model's training and serving data flows."
    },
    "technical_challenges": {
      "feature_ingestion": "The project involved ingesting many signals for real-time predictions. Near-real-time (NRT) features were used to speed up feature ingestion and simplify client logic.",
      "temporal_alignment": "Aligning all signals in temporal order for the time series model was challenging, but engineering workarounds and trade-offs helped overcome these issues.",
      "pipeline_design": "A single pipeline was used initially, with plans to partition airports later to reduce bias in statistical learning methods.",
      "queue_scaling": "Refactoring the legacy codebase for entity queue signals caused scaling issues, which were resolved by switching to partitioning by entity_id (driver_id)."
    }
  },
  "data_infrastructure": {
    "kafka_scaling": {
      "issue": "The amount of data emission was too large for the Kafka client to handle, leading to a hard tech constraint.",
      "solution": "The team switched from emitting on write to emission on peek, which caused data under-sampling during mid-night hours and potential duplicated events during peak hours."
    },
    "database_scaling": {
      "issue": "The NOSQL database docstore faced scaling issues due to an unbalanced partition scheme based on queue_id.",
      "solution": "The team switched to partitioning by entity_id (driver_id), which resolved the issue but introduced a trade-off requiring a materialized view for queue-level queries."
    }
  },
  "venue_marker_service": {
    "etr_serving": "Two Michelangelo clients are embedded in the Venue Marker service to call two different Michelangelo services and use an algorithmic heuristic to calculate the final ETR value.",
    "modular_design": "The design is modularized, allowing for the swapping out of the effective queue length model without significant prediction degradation during the first launching phase."
  },
  "future_work": {
    "improvements": "The team is exploring options to improve ETR precision/recall, including leveraging a time-series-based deep learning model to expand the prediction horizon across the entire day.",
    "extensions": "They are also looking to extend the ETR function on top of other Uber products, such as in-queue ETR calculation and better integration with current supply summoning tools at airports."
  },
  "acknowledgements": {
    "cross_functional_efforts": "The project achieved great success in most business metrics thanks to the cross-functional efforts by the Airport team within Rider Verticals in the Uber Mobility Org.",
    "ml_platform_support": "The Uber internal ML platform (Michelangelo) team provided critical support in onboarding training features and leveraging their serving, monitoring, and alerting capabilities at scale."
  },
  "team_members": {
    "michael_cai": {
      "role": "Senior Staff Software Engineer and Team Lead on the Airports team",
      "contributions": "Led many AI/ML projects and new growth initiatives like Share rides at airports and Smart Itineraries in the travel space."
    },
    "martina_balestra": {
      "role": "Senior Applied Scientist on the Airports team",
      "contributions": "Led demand and supply forecasting work."
    }
  },
  "category": "Engineering, Backend, Data / ML"
}

