{
  "feature_engineering": {
    "entity_level": {
      "description": "Entity-level feature engineering is used for anomaly detection at the individual entity level (e.g., user, vehicle, account).",
      "key_points": [
        "Entity-level features vary significantly across entities, requiring more sophisticated baselines and distribution shift management.",
        "Time-series analysis is used to normalize entities in the context of time, enabling comparison across entities to find anomalies.",
        "Feature importance algorithms are used to highlight noisy features and guide noise reduction.",
        "The feature space is large, but this provides a launching point for selecting relevant features based on the problem domain.",
        "Support for time-series analysis is critical for entity-level anomaly detection."
      ]
    },
    "event_level": {
      "description": "Event-level feature engineering is used for supervised models that analyze events (e.g., user logins, trip requests).",
      "key_points": [
        "Event-level features are more consistent across entities, making them easier to model with standard techniques.",
        "Feature engineering for event-level models focuses on capturing patterns in event sequences and interactions.",
        "The feature space is smaller compared to entity-level feature engineering, but it still requires careful selection of relevant features."
      ]
    }
  },
  "anomaly_detection": {
    "methods": {
      "unsupervised": {
        "description": "Unsupervised anomaly detection methods aim to separate anomalies from the normal population without labeled data.",
        "key_points": [
          "The system is built on top of Uber Michelangelo and offers multiple anomaly detection algorithms, including tree-based and neural net-based methods.",
          "Anomalies are identified as observations that stand out as distinct from the majority in a multi-dimensional space.",
          "The HAIFA algorithm is used to detect anomalies by analyzing feature distributions and identifying observations that fall into small buckets."
        ]
      },
      "supervised": {
        "description": "Supervised anomaly detection methods use labeled data to train models that can distinguish between normal and anomalous behavior.",
        "key_points": [
          "Supervised methods are used for event-level models where labeled data is available.",
          "These methods are less common in fraud detection due to the difficulty of labeling fraudulent behavior."
        ]
      }
    },
    "explanation": {
      "description": "Explainability is critical for fraud management, as it allows manual review agents to understand and assess the results of anomaly detection algorithms.",
      "key_points": [
        "HAIFA provides feature importance analysis, which helps manual reviewers understand which features are most indicative of fraud.",
        "Explainability is required to ensure that the results of anomaly detection algorithms are actionable and compliant with legal and internal policies.",
        "The HAIFA algorithm is designed to support streaming inference with minimal computational impact and to explain each anomalous observation separately."
      ]
    }
  },
  "haifa_algorithm": {
    "intuition": {
      "description": "HAIFA (Histogram Analysis of Important Features for Anomalies) is an algorithm that identifies anomalies by analyzing feature distributions.",
      "key_points": [
        "HAIFA identifies anomalies as observations that fall into small buckets in the histogram of feature distributions.",
        "The algorithm uses histograms to find if a particular observation is isolated in a particular direction.",
        "The bucket threshold is a hyperparameter that determines the maximum proportion of data that goes to a bucket."
      ]
    },
    "implementation": {
      "description": "HAIFA is implemented with an automated bucket threshold calculation to ensure that all anomalies have at least one important feature identified.",
      "key_points": [
        "The bucket threshold is calculated through binary search to find the minimum threshold such that all anomalous points have at least one important feature identified.",
        "The algorithm supports streaming inference with minimal computational impact.",
        "ML engineers can still use their own bucket threshold for experimentation if needed."
      ]
    }
  },
  "model_deployment": {
    "workflow": {
      "description": "Risk Entity Watch provides a streamlined workflow for ML engineers to train and deploy models in production.",
      "key_points": [
        "After a training set is created and defined in Apache Hive, all remaining tasks can be done in one Python DSL script.",
        "The platform supports interactive experimentation with hyperparameters, features, and datasets.",
        "Pre-generated EFG features are provided to enable efficient experimentation."
      ]
    },
    "tuning": {
      "description": "Model tuning is supported through a range of standardized plots and visualization tools.",
      "key_points": [
        "Standardized plots, such as pie charts of anomaly reasons and scatter plots of anomaly scores, help evaluate model performance.",
        "ML engineers can scrutinize features that trigger the detection of the majority of anomalies and adjust features that generate the most noise.",
        "The prioritization of features is determined by the aggregate results of feature importance derived by the HAIFA algorithm."
      ]
    }
  },
  "conclusion": {
    "description": "Risk Entity Watch is a platform that provides a developer-friendly approach to creating anomaly detection models, currently being used to help spot fraudulent entities within Uber.",
    "key_points": [
      "The platform supports both entity-level and event-level feature engineering, as well as unsupervised and supervised anomaly detection methods.",
      "HAIFA is a key algorithm used for anomaly detection and explanation, providing feature importance analysis to support manual review agents.",
      "The platform enables a fast cycle of continued model improvement through interactive experimentation and visualization tools."
    ]
  }
}

{
  "system": {
    "name": "uReview",
    "type": "AI Code Review Tool",
    "description": "An in-house AI code review tool developed by Uber to enhance code quality, reduce bugs, and improve developer productivity through automated review and feedback."
  },
  "features": {
    "code_review": {
      "description": "Reviews every commit as part of the CI process, analyzing source code for correctness, error handling, and best practices."
      },
    "language_support": {
      "description": "Supports multiple languages including Go, Java, Android, iOS, TypeScript, and Python."
      },
    "precision_focus": {
      "description": "Prioritizes precision over volume, delivering fewer but more useful comments that address real bugs and critical issues."
      },
    "feedback_loop": {
      "description": "Includes real-time developer feedback and automated evaluation to refine the system and improve comment quality."
      },
    "model_integration": {
      "description": "Uses a combination of models like Anthropic Claude-4-Sonnet and OpenAI o4-mini-high for comment generation and review grading."
      },
    "third_party_avoidance": {
      "description": "Avoids third-party tools due to architectural constraints, integration limitations, and cost efficiency."
      },
    "performance_metrics": {
      "description": "Tracks metrics like precision, recall, and F1 score to evaluate and improve the system's effectiveness."
      },
    "impact": {
      "description": "Maintains a sustained usefulness rate above 75%, saves thousands of hours annually, and reduces the number of bugs that reach human reviewers."
      },
    "deployment": {
      "description": "Deployed across all six of Uber’s monorepos, with reviews completed within a median of 4 minutes."
      },
    "continuous_improvement": {
      "description": "Uses feedback from both automated and manual evaluations to refine confidence thresholds, prompts, and filtering logic."
      },
    "scalability": {
      "description": "Designed to scale with Uber’s large codebase, handling over 65,000 diffs per month."
      },
    "developer_experience": {
      "description": "Focuses on delivering high-signal comments that developers value, such as correctness bugs and error handling, while avoiding low-impact stylistic suggestions."
      },
    "gradual_rollout": {
      "description": "Introduced in phases, with each stage instrumented with precision-recall dashboards and user-reported false-positive counts."
      },
    "integration": {
      "description": "Integrated with internal systems and data pipelines, including Apache Kafka and Apache Hive for feedback tracking and analysis."
      },
    "future_direction": {
      "description": "Plans to expand support for richer context, cover more review categories like performance and test coverage, and develop reviewer-focused tools."
      }
  },
  "lessons_learned": {
    "precision_over_volume": {
      "description": "Comment quality matters more than quantity. Developers lose trust in tools that generate low-quality or irrelevant suggestions."
      },
    "feedback_instrumentation": {
      "description": "Real-time feedback is essential for tuning the system. Embedding simple rating links and linking feedback to metadata enables targeted improvements."
      },
    "guardrails_and_prompts": {
      "description": "Even with high-performing models, unfiltered outputs can lead to hallucinations and inconsistencies. Multi-stage prompts and post-processing are critical for reliability."
      },
    "developer_preferences": {
      "description": "Developers prefer comments that address correctness, error handling, and best practices over stylistic or readability nits."
      },
    "bug_detection_over_system_design": {
      "description": "uReview is better at catching bugs from code analysis than assessing system design, which requires access to additional artifacts like PRs and documentation."
      },
    "trust_building": {
      "description": "Gradual rollout and data-driven iteration help build trust and ensure the system is refined based on real-world use."
      }
  },
  "impact_summary": {
    "usefulness_rate": "Sustained above 75%",
    "time_savings": "Approximately 1,500 hours saved weekly, equivalent to nearly 39 developer years annually",
    "bug_reduction": "Reduces the number of bugs that reach human reviewers",
    "model_performance": "Achieves the highest F1 score with a combination of Anthropic Claude-4-Sonnet and OpenAI o4-mini-high"
  },
  "evaluation": {
    "automated": {
      "description": "Evaluates if a comment is addressed by re-running uReview five times on the final commit."
      },
    "manual": {
      "description": "Uses a curated benchmark of commits with known issues to evaluate precision, recall, and F1 scores against human-labeled annotations."
      }
  },
  "third_party_comparison": {
    "reasons_for_in_house": {
      "github_dependency": "Most third-party tools require GitHub, but Uber uses Phabricator.",
      "integration_issues": "Third-party tools struggle with integration with internal systems and suffer from false positives and low-value true positives.",
      "cost_efficiency": "Running uReview is significantly cheaper than using third-party tools at scale."
      }
  },
  "future_plans": {
    "richer_context": {
      "description": "Expand support for richer context, including access to past PRs, feature flags, and technical documentation."
      },
    "additional_review_categories": {
      "description": "Cover more review categories like performance and test coverage."
      },
    "reviewer_tools": {
      "description": "Develop reviewer-focused tools to enhance the code review process."
      }
  }
}

